VALUES
  ('medical-tech-moex-16338', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '病人兩星期前輸過血，再次需要輸血。但病人血清與所有測試細胞（臍帶血除外），包括抗體篩檢 細胞以及抗體鑑定細胞在立即離心均有（3+）反應，在抗球蛋白期也有（1+）反應，自體細胞對照 也有相似反應。應如何做交叉試驗？', '["應用PEG加強反應", "應做預溫試驗", "病人血清應做自體細胞吸附後再做交叉試驗", "鑑定出抗體，並由稀有捐血者中要求供應血液"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 73, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-16339', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '某對夫妻及其新生嬰兒的Rh系統測試結果如下：夫D(0)C(+)E(0)c(+)e(+)weak D(+)；妻D(0)C(0)E (0)c(+)e(+)weak D(0)；小孩D(+)C(0)E(0)c(+)e(+)。則下列結論何者正確？', '["此位先生並不是小孩的親生父親", "此位先生可以證明為小孩的父親", "無法排除“此先生為小孩的親生父親之可能性", "小孩的D(+)為偽陽性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 74, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-16340', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '基因型為CDe/cde（夫）與cde/cde（妻）組合，小孩為Rh陰性的機率為：', '["0%", "25%", "50%", "75%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 75, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-16341', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '某病人的Rh系統測試結果如下：D(+)C(+)E(0)c(+)e(+)。其最可能的基因型為何？', '["R1R1", "R1r", "R1R2", "R0r’"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 76, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-16342', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '下列有關血庫品管測試的敘述，何者錯誤？', '["Gel Test比傳統方法更具標準化", "抗血清力價測試有凝集即判為陽性", "品管測試方法要與平時方法一致", "Anti-D抗血清品管需大於32倍以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 77, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-16343', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關血液分離術的捐血者的要求，下列敘述何者正確？', '["體重50公斤即可做連續性流動儀器之分離", "間隔須逾三個月以上", "只要健康允許每年捐出血漿量不受限制", "每次血漿只能捐250 ml"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 78, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-16344', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '下列有關ABO血型檢查的敘述，何者錯誤？', '["年齡會影響血型檢查的反應強度", "血型抗體試劑效價已達256倍，即可用於日常檢測上", "必須使用洗滌過的紅血球測定", "溶血檢體不能用於血型測定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 79, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-16345', 'medical-tech', 'medical-tech-moex-098-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '下列有關米田堡血型系列（Miltenberger series, Mi）的敘述，何者錯誤？', '["其形成為GPA（Glycophorin A）與GPB（Glycophorin B）的雜交蛋白（Hybrid protein）", "Anti-“Mia”為臺灣最常被鑑定的抗體之一", "Anti-“Mia”與Mi III抗原有關", "Mi III之生化結構主要為GPA/GPB雜交蛋白GP ABA之形式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:04+00:00", "source_pdf_sha1": "a429f4c9b593", "answer_pdf_sha1": "280adc8905e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 80, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
